using UnityEngine;

[RequireComponent(typeof(Collider2D))]
public class WaterDetector : MonoBehaviour
{
    [Tooltip("Layers consideradas �gua")]
    public LayerMask waterLayer;

    [Header("Checks")]
    [Tooltip("Ponto que representa a cabe�a (se estiver dentro da �gua, est� submerso).")]
    public Transform headCheck;

    [Tooltip("Offset autom�tico da cabe�a se headCheck n�o for definido.")]
    public Vector2 autoHeadOffset = new Vector2(0f, 0.6f);

    public bool IsInWater { get; private set; }
    public bool IsSubmerged { get; private set; }
    public bool IsAtSurface => IsInWater && !IsSubmerged;

    /// <summary>Disparado quando o player passa de "não-submerso" para "submerso" (cabeça debaixo de água).</summary>
    public event System.Action EnteredSubmerged;

    /// <summary>Disparado quando o player passa de "submerso" para "não-submerso" (saiu de baixo de água ou saiu da água).</summary>
    public event System.Action ExitedSubmerged;

    /// <summary>Disparado quando o player entra em contacto com a água (IsInWater passa de false a true).</summary>
    public event System.Action EnteredWater;

    /// <summary>Disparado quando o player sai completamente da água (IsInWater passa de true a false).</summary>
    public event System.Action ExitedWater;

    private int waterContacts = 0;
    private Animator anim;

    private void Awake()
    {
        anim = GetComponent<Animator>();

        if (headCheck == null)
        {
            var hc = new GameObject("HeadCheck");
            hc.transform.SetParent(transform);
            hc.transform.localPosition = autoHeadOffset;
            headCheck = hc.transform;
        }
    }

    private void Update()
    {
        // S� faz sentido calcular submerso se estiver em �gua
        if (!IsInWater)
        {
            SetSubmerged(false);
            return;
        }

        // Se a cabe�a est� dentro do water layer -> submerso
        bool submergedNow = Physics2D.OverlapPoint(headCheck.position, waterLayer) != null;
        SetSubmerged(submergedNow);
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!IsWater(other)) return;

        waterContacts++;
        if (!IsInWater)
        {
            IsInWater = true;
            if (anim) anim.SetBool("IsInWater", true);
            EnteredWater?.Invoke();
        }
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!IsWater(other)) return;

        waterContacts = Mathf.Max(0, waterContacts - 1);
        bool wasInWater = IsInWater;
        IsInWater = waterContacts > 0;

        if (anim) anim.SetBool("IsInWater", IsInWater);

        if (!IsInWater)
        {
            SetSubmerged(false);
            if (wasInWater) ExitedWater?.Invoke();
        }
    }

    private void SetSubmerged(bool value)
    {
        if (IsSubmerged == value) return;
        IsSubmerged = value;

        if (anim) anim.SetBool("IsSubmerged", IsSubmerged);
        if (anim) anim.SetBool("IsAtSurface", IsAtSurface);

        if (IsSubmerged) EnteredSubmerged?.Invoke();
        else             ExitedSubmerged?.Invoke();
    }

    private bool IsWater(Collider2D other)
    {
        int mask = 1 << other.gameObject.layer;
        return (waterLayer.value & mask) != 0;
    }

    private void OnDrawGizmosSelected()
    {
        if (headCheck == null) return;
        Gizmos.color = Color.cyan;
        Gizmos.DrawWireSphere(headCheck.position, 0.05f);
    }
}
